---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"
import CheckIcon from "lucide-static/icons/check.svg"

import { cn } from "@/lib/utils"
import {
  Avatar,
  AvatarFallback,
  AvatarGroup,
  AvatarImage,
} from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import { Rating } from "@/components/ui/rating"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  features: string[]
  buttons: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  socialProof: {
    avatars: {
      image?: ImageMetadata
      initials: string
      name?: string
    }[]
    rating: number
    text: string
  }
  image: {
    src: ImageMetadata
    alt: string
  }
}

const {
  class: className,
  title,
  description,
  features,
  buttons,
  socialProof,
  image,
} = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer
    class="grid gap-12 lg:grid-cols-[2fr_3fr] lg:items-center lg:gap-0"
  >
    <div class="flex flex-col gap-6 lg:pr-12">
      <div class="flex flex-col gap-4">
        <h1
          class="text-foreground text-4xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-5xl"
        >
          {title}
        </h1>
        <p class="text-muted-foreground text-lg leading-relaxed">
          {description}
        </p>
      </div>
      <ul class="flex flex-col gap-3">
        {
          features.map((feature) => (
            <li class="flex items-center gap-3 text-sm">
              <CheckIcon class="text-primary size-4 shrink-0" />
              {feature}
            </li>
          ))
        }
      </ul>
      <div class="flex flex-wrap gap-3">
        {
          buttons.map(({ href, label, ...button }, index) => (
            <Button
              as="a"
              href={href}
              size="lg"
              variant={
                button.variant ?? (index === 0 ? "default" : "secondary")
              }
              {...button}
            >
              {label}
            </Button>
          ))
        }
      </div>
      <div class="flex items-center gap-3">
        <AvatarGroup>
          {
            socialProof.avatars.map((avatar) => (
              <Avatar class="ring-background size-11 ring">
                <AvatarImage
                  src={avatar.image}
                  alt={avatar.name ?? avatar.initials}
                />
                <AvatarFallback>{avatar.initials}</AvatarFallback>
              </Avatar>
            ))
          }
        </AvatarGroup>
        <div class="flex flex-col gap-0.5">
          <Rating value={socialProof.rating} />
          <span class="text-muted-foreground text-xs">{socialProof.text}</span>
        </div>
      </div>
    </div>
    <Image
      src={image.src}
      alt={image.alt}
      class="aspect-4/3 w-full rounded-xl border object-cover"
      widths={[640, 960, 1280]}
      sizes="(min-width: 1024px) 60vw, 100vw"
      loading="eager"
    />
  </SectionContainer>
</Section>
